 6→impl TodoTitle {
 7→    pub fn parse(input: String) -> Result<Self, TodoTitleError> {
 8→        let trimmed = input.trim().to_string();
 9→        if trimmed.is_empty() {
10→            return Err(TodoTitleError::Empty);
11→        }
12→        if trimmed.len() > MAX_TITLE_LENGTH {
13→            return Err(TodoTitleError::TooLong {
14→                max: MAX_TITLE_LENGTH,
15→                actual: trimmed.len(),
16→            });
17→        }
18→        Ok(Self(trimmed))
19→    }
20→
21→    pub fn as_str(&self) -> &str {
22→        &self.0
23→    }
24→}
25→
26→#[derive(Debug, thiserror::Error, PartialEq)]
27→pub enum TodoTitleError {
28→    #[error("Todo title cannot be empty")]
29→    Empty,
30→    #[error("Todo title too long (max {max}, got {actual})")]
31→    TooLong { max: usize, actual: usize },
32→}
