        Ok(()) => {
            if htmx {
                let context =
                    crate::infrastructure::context_repository::find_context_by_id(&pool, &ctx_id)
                        .await
                        .map_err(|e| {
                            ContextError::Unexpected(anyhow::anyhow!("Database error: {e}"))
                        })?
                        .ok_or_else(|| {
                            ContextError::Unexpected(anyhow::anyhow!("Context not found"))
                        })?;

