// ---- User Isolation ----

#[tokio::test]
async fn users_cannot_see_each_others_contexts() {
    let app = spawn_app().await;

    let client_a =
        register_and_login(&app.address, "ctx_a@example.com", "securepassword123").await;
    let client_b =
        register_and_login(&app.address, "ctx_b@example.com", "securepassword123").await;

