#[tokio::test]
async fn htmx_post_context_returns_fragment_with_announce_header() {
    let app = spawn_app().await;
    let client =
        register_and_login(&app.address, "htmxctx@example.com", "securepassword123").await;

    let response = client
        .post(format!("{}/contexts", &app.address))
