    // Verify context is gone
    let response = client
        .get(format!("{}/contexts", &app.address))
        .send()
        .await
        .expect("Failed to GET /contexts");

    let body = response.text().await.unwrap();
    assert!(
        !body.contains("@deleteme"),
        "Deleted context should no longer appear"
    );
}

